创建一个客户端和服务端的应用程序，以实现文件传输、实时在线人数显示和图片预览，是一个非常复杂的任务，需要的代码量很大。下面我会以高度摘要的代码块来描述这个系统的概述，但请注意，这不是一个完整的实现。完整的实现需要深厚的计算机网络知识、编程技能和时间来完成。此外，环境配置和库的安装也对最终实现至关重要。

**服务端 (JavaScript/Node.js)**

首先，我们使用Node.js及其`socket.io`库创建一个简单的WebSocket服务端，支持客户端之间消息传递及文件分享功能。

```js
const express = require('express');
const http = require('http');
const socketIO = require('socket.io');
const fs = require('fs');

const app = express();
const server = http.createServer(app);
const io = socketIO(server);

let onlineUsers = {}; // 存在线人数的字典，键是socket.id，值是用户名

io.on('connection', (socket) => {
    // 当有用户连接时
    socket.on('register', ({ username }) => {
        onlineUsers[socket.id] = username;
        updateOnlineUsers();
    });

    // 当用户断线时
    socket.on('disconnect', () => {
        delete onlineUsers[socket.id];
        updateOnlineUsers();
    });

    // 文件接收并保存
    socket.on('file', ({ name, data }) => {
        const buffer = Buffer.from(data);
        fs.writeFile(`./uploads/${name}`, buffer, () => {
            io.emit('file', { name, url: `/uploads/${name}` });
        });
    });

    // 获取在线用户信息
    function updateOnlineUsers() {
        io.emit('onlineUsers', Object.values(onlineUsers));
    }

    // ... 添加更多的事件和处理逻辑
});

server.listen(3000, () => {
    console.log('Server listening on port 3000');
});
```

**客户端 (HTML/JavaScript)**

客户端可以是一个简单的HTML页面，使用Socket.IO客户端库与服务器进行通信，并使用JavaScript进行DOM操作来更新页面内容。

```html
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Client</title>
</head>
<body>
    <div>在线人数：<span id="online-count">0</span></div>
    <div id="online-users"></div>

    <!-- 图片预览 -->
    <div>
        <input type="file" id="image-input" accept="image/*">
        <img id="image-preview" src="" alt="Image Preview">
    </div>

    <!-- 文件上传 -->
    <div>
        <input type="file" id="file-input">
        <button id="file-upload">上传</button>
    </div>

    <!-- 文件链接 -->
    <div id="file-links"></div>

    <script src="/socket.io/socket.io.js"></script>
    <script>
        const socket = io();

        socket.emit('register', { username: 'YourUsername' }); // 更换为用户名称

        socket.on('onlineUsers', (users) => {
            // 更新在线人数和用户名
            document.getElementById('online-count').innerText = users.length.toString();
            const usersList = document.getElementById('online-users');
            usersList.innerHTML = users.map((user) => `<div>${user}</div>`).join('');
        });

        socket.on('file', ({ name, url }) => {
            // 接收到新文件时添加到页面上
            const link = document.createElement('a');
            link.href = url;
            link.innerText = name;
            document.getElementById('file-links').appendChild(link);
        });

        // 绑定图片预览事件
        document.getElementById('image-input').addEventListener('change', (event) => {
            const file = event.target.files[0];
            const reader = new FileReader();
            reader.onload = (e) => {
                document.getElementById('image-preview').src = e.target.result;
            };
            reader.readAsDataURL(file);
        });

        // 绑定文件上传事件
        document.getElementById('file-upload').addEventListener('click', () => {
            const file = document.getElementById('file-input').files[0];
            const reader = new FileReader();
            reader.onload = (e) => {
                socket.emit('file', {
                    name: file.name,
                    data: e.target.result
                });
            };
            reader.readAsArrayBuffer(file);
        });

    </script>
</body>
</html>
```

