**修改后的服务端示例 (Node.js)：**

```js
// server.js
const express = require('express');
const http = require('http');
const socketIO = require('socket.io');
const fs = require('fs');
const path = require('path');

const app = express();
const server = http.createServer(app);
const io = socketIO(server);

let onlineUsers = {};

app.use('/uploads', express.static('uploads')); // 使'uploads'文件夹公开

io.on('connection', (socket) => {
    socket.on('register', ({ username }) => {
        onlineUsers[socket.id] = username;
        updateOnlineUsers();
    });

    socket.on('disconnect', () => {
        delete onlineUsers[socket.id];
        updateOnlineUsers();
    });

    socket.on('message', (text) => {
        const sender = onlineUsers[socket.id] || 'Anonymous';
        io.emit('message', { sender, text });
    });

    socket.on('file', ({ name, data }) => {
        const buffer = Buffer.from(data, 'base64');
        const safeName = makeSafe(name);
        fs.writeFile(path.join(__dirname, 'uploads', safeName), buffer, (err) => {
            if (err) {
                console.error('Write file error:', err);
                return;
            }
            io.emit('file', { name: safeName, url: `/uploads/${safeName}` });
        });
    });

    function updateOnlineUsers() {
        io.emit('onlineUsers', Object.values(onlineUsers));
    }

    // Simple function to prevent directory traversal or other malicious file names
    function makeSafe(filename) {
        return filename.replace(/[^a-z0-9_\-\.]/gi, '_');
    }
});

server.listen(3000, () => {
    console.log('Server listening on port 3000');
});
```

请确保先安装所有必要的Node.js模块（`express`, `socket.io`, `fs`, `path`）。

