```javascript
// server.js
const fs = require('fs');
const http = require('http');
const WebSocketServer = require('ws').WebSocketServer;
const path = require('path');
const uuid = require('uuid');

const server = http.createServer((req, res) => {
    res.writeHead(404);
    res.end();
});

const wss = new WebSocketServer({ server });

wss.on('connection', ws => {
    ws.on('message', message => {
        const data = JSON.parse(message);

        if (data.type === 'text') {
            broadcast(JSON.stringify({type: data.type, name: data.name, message: data.message}));
        } else if (data.type === 'file' || data.type === 'image') {
            const uploadPath = 'uploads/';

            // 确保上传路径存在
            if (!fs.existsSync(uploadPath)) {
                fs.mkdirSync(uploadPath);
            }

            // 提取文件格式并创建唯一文件名
            const base64Data = data.filedata.split(';base64,').pop();
            const extension = data.originalName.split('.').pop();
            const filename = uuid.v4() + '.' + extension;
            const filepath = path.join(uploadPath, filename);

            fs.writeFile(filepath, base64Data, {encoding: 'base64'}, (err) => {
                if (err) {
                    console.error('File could not be saved: ', err);
                    ws.send(JSON.stringify({type: 'error', message: 'File could not be saved'}));
                } else {
                    broadcast(JSON.stringify({
                        type: data.type,
                        name: data.name,
                        originalName: data.originalName,
                        filepath: filepath
                    }));
                }
            });
        }
    });

    ws.on('close', () => {
        console.log('WebSocket was closed');
    });
});

function broadcast(message) {
    wss.clients.forEach(client => {
        if (client.readyState === WebSocketServer.OPEN) {
            client.send(message);
        }
    });
}

const PORT = 3000;
server.listen(PORT, () => {
    console.log(`Server is running on port ${PORT}`);
});
```

