// 仅包含修改的部分，其余部分 (如connectToServer、clearChat、closeConnection等) 保持不变

function sendMessage() {
    const messageInput = document.getElementById('message');
    const message = messageInput.value.trim();
    if (message && socket.readyState === WebSocket.OPEN) {
        addMessage(name, message); // 显示你发送的消息
        socket.send(JSON.stringify({type: 'text', name: name, message: message}));
        messageInput.value = ''; // 清空输入框
    }
}

function uploadImage() {
    const imageInput = document.getElementById('image-input');
    const imageFile = imageInput.files[0];
    if (imageFile && socket.readyState === WebSocket.OPEN) {
        const reader = new FileReader();
        reader.onload = function(event) {
            const imageContent = event.target.result;
            addFile(name, imageFile.name, imageContent); // 显示你上传的图片
            socket.send(JSON.stringify({
                type: 'image',
                name: name,
                originalName: imageFile.name,
                filedata: imageContent
            }));
        };
        reader.readAsDataURL(imageFile);
    }
}

function uploadFile() {
    const fileInput = document.getElementById('file-input');
    const file = fileInput.files[0];
    if (file && socket.readyState === WebSocket.OPEN) {
        const reader = new FileReader();
        reader.onload = function(event) {
            const fileContent = event.target.result;
            addFile(name, file.name, fileContent); // 显示你上传的文件
            socket.send(JSON.stringify({
                type: 'file',
                name: name,
                originalName: file.name,
                filedata: fileContent
            }));
        };
        reader.readAsDataURL(file);
    }
}
