**服务端代码 (Node.js)**:

```javascript
// server.js
const path = require('path');
const fs = require('fs');
const http = require('http');
const WebSocket = require('ws');
const express = require('express');
const multer = require('multer');
const app = express();

// 为文件上传配置multer
const storage = multer.diskStorage({
  destination: function (req, file, cb) {
    cb(null, 'uploads/')
  },
  filename: function (req, file, cb) {
    const uniqueSuffix = Date.now() + '-' + Math.round(Math.random() * 1E9);
    cb(null, file.fieldname + '-' + uniqueSuffix + path.extname(file.originalname));
  }
});

const upload = multer({ storage: storage });

// 提供静态文件访问
app.use(express.static(path.join(__dirname, 'public')));
app.use('/uploads', express.static('uploads'));

// 文件上传请求处理
app.post('/upload', upload.single('file'), function (req, res, next) {
  // req.file 是 `file` 文件的信息
  // req.body 将具有文本域数据，如果存在的话
  if (!req.file) {
    return res.status(400).send('No file uploaded.');
  }
  return res.status(200).json({ filePath: `/uploads/${req.file.filename}` });
});

const server = http.createServer(app);
const wss = new WebSocket.Server({ server });

wss.on('connection', function connection(ws) {
  ws.on('message', function incoming(message) {
    // 解析消息为JSON
    const data = JSON.parse(message);

    // 处理不同类型的消息
    if (data.type === 'text') {
      // 广播文本消息到所有客户端
      wss.clients.forEach(function each(client) {
        if (client.readyState === WebSocket.OPEN) {
          client.send(JSON.stringify(data));
        }
      });
    } else if (data.type === 'image' || data.type === 'file') {
      // 对于文件，我们只存储文件路径返回给客户端 - 实际的文件处理被分离到了上传的HTTP请求中
      wss.clients.forEach(function each(client) {
        if (client.readyState === WebSocket.OPEN) {
          client.send(JSON.stringify({
            type: data.type,
            name: data.name,
            url: data.filePath,
            isImage: data.type === 'image'
          }));
        }
      });
    }
  });
});

const PORT = 3000;
server.listen(PORT, function() {
  console.log(`Server is running on http://localhost:${PORT}`);
});
```

请注意，以下步骤必须进行：

1. 在项目根目录下创建 `uploads` 文件夹作为文件上传存储位置。
2. 确保所有的客户端使用你部署的服务端的正确地址。
3. 在部署此代码之前，请先安装必要的Node.js包：

```bash
npm install ws express multer
```

此服务端代码使用了 `ws` 提供WebSocket服务，`express` 处理HTTP请求，以及 `multer` 处理文件上传。服务端会把接收到的文件保存在 `uploads` 文件夹中，并将文件的访问URL发送给所有连接的WebSocket客户端。

这样，客户端提交任何信息（包括普通消息、图片、文件）时都能被其他客户端收到并在他们的界面上显示。文件和图片通过HTTP POST上传到服务端并且存储，然后服务端将文件的URL发送给所有连接的WebSocket客户端。

